    difficulty: 'Medium', reward: 180, kpId: 'kp-6.1-01', sectionId: 'geometry',
    tutorialSteps: [
      { text: { zh: '刘备：为什么要学勾股定理？\n攻城梯要搭到城墙上——太短够不着，太长会翻倒。\n知道墙高和距离，勾股定理算出梯子要多长！', en: 'Liu Bei: "Why learn Pythagoras?\nThe siege ladder must reach the wall — too short and it falls short, too long and it topples.\nKnow the wall height and distance, and Pythagoras tells you the ladder length!"' }, highlightField: 'c' },
      { text: { zh: '刘备：勾股定理\n$$a^2 + b^2 = c^2$$\n$a, b$ 是直角边，$c$ 是斜边（最长边）。\n就像一块方砖拼出两块小方砖！', en: 'Liu Bei: "Pythagoras\' Theorem\n$$a^2 + b^2 = c^2$$\n$a, b$ are the short sides, $c$ is the hypotenuse (longest side).\nLike two small squares combining into one large square!"' }, highlightField: 'c' },
      { text: { zh: '刘备：代入\n$a$ 和 $b$ 已知，求 $c$：\n$c = \\sqrt{a^2 + b^2}$', en: 'Liu Bei: "Substitute\n$a$ and $b$ are known, find $c$:\n$c = \\sqrt{a^2 + b^2}$"' }, highlightField: 'c' },
      { text: { zh: '刘备：计算\n先平方，再相加，最后开根号。', en: 'Liu Bei: "Calculate\nSquare first, then add, then take the square root."' }, highlightField: 'c' },
      { text: { zh: '刘备：答案\n攻城梯长度确定！', en: 'Liu Bei: "Answer\nSiege ladder length confirmed!"' }, highlightField: 'c' },
      { text: { zh: '刘备：验算\n$a^2 + b^2 = c^2$？代入检查 ✓', en: 'Liu Bei: "Verify\n$a^2 + b^2 = c^2$? Substitute and check ✓"' }, highlightField: 'c' },
    ],
    secret: { concept: { zh: '直角三角形中，斜边的平方等于两条直角边的平方之和。', en: 'In a right triangle, hypotenuse² = sum of the other two sides².' }, formula: '$c = \\sqrt{a^2 + b^2}$', tips: [{ zh: '关羽提示：攻城梯太短搭不上去，太长又会倒！', en: 'Guan Yu Tip: Ladder too short won\'t reach; too long will topple!' }] },
    storyConsequence: { correct: { zh: '攻城梯长度刚好！士兵成功攀上城头！', en: 'Ladder length is perfect! Soldiers scale the wall!' }, wrong: { zh: '长度还差一点——检查公式里的数字对不对？', en: 'Wrong ladder length — siege fails...' } },
